use strict;
use warnings;
use Digest::SHA qw(sha1_hex);
use File::Path qw(make_path remove_tree);
use File::Copy qw(copy);
use File::Spec;

# Constants
my $MINIGIT_DIR      = '.minigit';
my $OBJECTS_DIR      = "$MINIGIT_DIR/objects";
my $INDEX_FILE       = "$MINIGIT_DIR/index";
my $HEAD_FILE        = "$MINIGIT_DIR/HEAD";
my $LOG_FILE         = "$MINIGIT_DIR/log";

sub usage {
    print "Usage: ./minigit <command> [args]\n";
    exit 1;
}

sub ensure_minigit {
    unless (-d $MINIGIT_DIR) {
        print STDERR "Not a minigit repository (or any parent up to mount point)\n";
        exit 1;
    }
}

sub cmd_init {
    if (-d $MINIGIT_DIR) {
        print STDERR "minigit repository already exists\n";
        exit 1;
    }
    make_path($OBJECTS_DIR);
    open(my $fh, '>', $INDEX_FILE) or die "Cannot initialize index: $!";
    close($fh);
    open(my $fh2, '>', $HEAD_FILE) or die "Cannot initialize HEAD: $!";
    print $fh2 '';
    close($fh2);
    open(my $fh3, '>', $LOG_FILE) or die "Cannot initialize log: $!";
    close($fh3);
    print "Initialized empty minigit repository in $MINIGIT_DIR\n";
}

sub read_index {
    open(my $fh, '<', $INDEX_FILE) or die "Missing index!";
    my %index;
    while(my $line = <$fh>) {
        chomp $line;
        my ($fname, $hash) = split /\s+/, $line, 2;
        $index{$fname} = $hash;
    }
    close($fh);
    return %index;
}

sub write_index {
    my (%index) = @_;
    open(my $fh, '>', $INDEX_FILE) or die "Cannot write index: $!";
    for my $fname (sort keys %index) {
        print $fh "$fname $index{$fname}\n";
    }
    close($fh);
}

sub cmd_add {
    ensure_minigit();
    my @files = @ARGV;
    if (!@files) {
        print STDERR "No file specified.\n";
        exit 1;
    }
    my %index = read_index();
    foreach my $file (@files) {
        if (! -f $file) {
            print STDERR "File '$file' does not exist.\n";
            exit 1;
        }
        open(my $fh, '<', $file) or die $!;
        binmode $fh;
        my $content = do { local $/; <$fh> };
        close($fh);
        my $hash = sha1_hex($content);
        # Store the object if not yet stored
        my $obj_path = "$OBJECTS_DIR/$hash";
        unless (-e $obj_path) {
            open(my $ofh, '>', $obj_path) or die $!;
            binmode $ofh;
            print $ofh $content;
            close($ofh);
        }
        # Update index
        $index{$file} = $hash;
    }
    write_index(%index);
}

sub read_head {
    open(my $fh, '<', $HEAD_FILE) or die $!;
    my $commit = <$fh>;
    chomp($commit) if defined $commit;
    close($fh);
    return $commit;
}

sub write_head {
    my ($commit) = @_;
    open(my $fh, '>', $HEAD_FILE) or die $!;
    print $fh "$commit\n";
    close($fh);
}

sub read_log {
    my @log_entries;
    open(my $fh, '<', $LOG_FILE) or return ();
    while (my $line = <$fh>) {
        chomp $line;
        push @log_entries, $line;
    }
    close($fh);
    return @log_entries;
}

sub append_log {
    my ($commit, $msg) = @_;
    open(my $fh, '>>', $LOG_FILE) or die $!;
    print $fh "$commit $msg\n";
    close($fh);
}

sub write_commit {
    my ($hash, $parent, $msg, $index_ref) = @_;
    my $filename = "$OBJECTS_DIR/$hash.commit";
    open(my $fh, '>', $filename) or die $!;
    print $fh "parent $parent\n" if $parent;
    print $fh "msg $msg\n";
    for my $fname (sort keys %$index_ref) {
        print $fh "file $fname $index_ref->{$fname}\n";
    }
    close($fh);
}

sub get_commit {
    my ($hash) = @_;
    my $filename = "$OBJECTS_DIR/$hash.commit";
    return undef unless -f $filename;
    open(my $fh, '<', $filename) or die $!;
    my %commit;
    $commit{files} = {};
    while (my $line = <$fh>) {
        chomp $line;
        if ($line =~ /^parent (\w{40})$/) {
            $commit{parent} = $1;
        } elsif ($line =~ /^msg (.*)$/) {
            $commit{msg} = $1;
        } elsif ($line =~ /^file (\S+) (\w{40})$/) {
            $commit{files}->{$1} = $2;
        }
    }
    close($fh);
    return \%commit;
