        print STDERR "Usage: ./minigit commit -m <msg>\n";
        exit 1;
    }
    my $msg = $ARGV[1];
    my %index = read_index();
    # Compose a snapshot string for commit hash
    my $head = read_head();
    my $snapshot = '';
    $snapshot .= "$_ $index{$_}\n" for sort keys %index;
    $snapshot .= "parent $head\n" if $head;
    $snapshot .= "msg $msg\n";
    my $commit_hash = sha1_hex($snapshot);
    write_commit($commit_hash, $head, $msg, \%index);
    write_head($commit_hash);
    append_log($commit_hash, $msg);
    print "Committed as $commit_hash\n";
}

sub cmd_log {
    ensure_minigit();
    my @log = read_log();
    for (reverse @log) {
        my ($commit, $msg) = split(/ /, $_, 2);
        print "$commit $msg\n";
    }
}

