    ensure_minigit();
    my %index = read_index();
    my $head = read_head();
    my %commit_files = ();
    if ($head) {
        my $commit = get_commit($head);
        %commit_files = %{$commit->{files}} if $commit;
    }
    # Find staged, unstaged, untracked
    my %workspace;
    opendir(my $dh, ".") or die;
    for my $file (readdir($dh)) {
        next if $file =~ /^\./ || -d $file || $file eq "minigit";
        $workspace{$file} = 1;
    }
    closedir($dh);
    # Staged for commit
    for my $file (sort keys %index) {
        if (!exists $commit_files{$file} || $index{$file} ne $commit_files{$file}) {
            print "staged: $file\n";
        }
    }
    # Unstaged
    for my $file (sort keys %index) {
        next unless -f $file;
        open(my $fh, '<', $file) or next;
        binmode $fh;
        my $content = do { local $/; <$fh> };
        close($fh);
        my $hash = sha1_hex($content);
        if ($index{$file} ne $hash) {
            print "modified: $file\n";
        }
    }
    # Untracked
    for my $file (sort keys %workspace) {
        next if exists $index{$file};
        print "untracked: $file\n";
    }
}

sub cmd_checkout {
    ensure_minigit();
    my $commit = $ARGV[0];
    unless ($commit) {
        print STDERR "Usage: ./minigit checkout <commit>\n";
        exit 1;
    }
    unless ($commit =~ /^[0-9a-f]{40}$/) {
        print STDERR "Invalid commit hash\n";
        exit 1;
    }
    my $commit_obj = get_commit($commit);
    unless ($commit_obj) {
        print STDERR "Unknown commit $commit\n";
        exit 1;
    }
    my %files = %{$commit_obj->{files}};
    # Overwrite working directory
    for my $file (keys %files) {
        my $objfile = "$OBJECTS_DIR/$files{$file}";
        unless (-f $objfile) {
            print STDERR "Object missing for $file ($files{$file})\n";
            exit 1;
        }
        copy($objfile, $file) or die "Couldn't copy $file: $@";
    }
    # Remove any files in the index but not in this commit
    my %index = read_index();
    for my $file (keys %index) {
        unless (exists $files{$file}) {
            unlink $file if -f $file;
        }
    }
    # Update index and HEAD to that commit
    write_index(%files);
    write_head($commit);
    print "Checked out $commit\n";
}

# Command dispatch

my $cmd = shift @ARGV or usage();

if    ($cmd eq 'init')     { cmd_init(); }
elsif ($cmd eq 'add')      { cmd_add(); }
elsif ($cmd eq 'commit')   { cmd_commit(); }
elsif ($cmd eq 'log')      { cmd_log(); }
elsif ($cmd eq 'status')   { cmd_status(); }
elsif ($cmd eq 'checkout') { cmd_checkout(); }
else                       { usage(); }

exit 0;
```

